1	// Valid registry name pattern: @namespace where namespace is alphanumeric with hyphens/underscores
2	const REGISTRY_PATTERN = /^(@[a-zA-Z0-9](?:[a-zA-Z0-9-_]*[a-zA-Z0-9])?)\/(.+)$/
3	
4	export function parseRegistryAndItemFromString(name: string) {
5	  if (!name.startsWith("@")) {
6	    return {
7	      registry: null,
8	      item: name,
9	    }
10	  }
11	
12	  const match = name.match(REGISTRY_PATTERN)
13	  if (match) {
14	    return {
15	      registry: match[1],
16	      item: match[2],
17	    }
18	  }
19	
20	  return {
21	    registry: null,
22	    item: name,
23	  }
24	}
