# Plan: Add Stepper Compound Component

## Context

The shadcn/ui registry at `apps/v4/registry/bases/radix/` currently has no Stepper component for multi-step wizard / onboarding flows. We need to add one following all existing patterns exactly — `"use client"` directive, `data-slot` attributes, `cn-` CSS marker prefixes, Tailwind v4 `data-[orientation]` variants via the project-defined `data-horizontal:`/`data-vertical:` shorthands, `IconPlaceholder` for multi-icon-library support, React context for inter-sub-component state, and the standard `_registry.ts` entry format.

No existing files are to be modified except for appending new registry entries to the two `_registry.ts` files.

---

## Files to Create

| File | Purpose |
|------|---------|
| `apps/v4/registry/bases/radix/ui/stepper.tsx` | Component implementation |
| `apps/v4/registry/bases/radix/examples/stepper-example.tsx` | Demo example |

## Files to Modify (append only)

| File | Change |
|------|--------|
| `apps/v4/registry/bases/radix/ui/_registry.ts` | Add `stepper` entry (alphabetically between `spinner` and `switch`) |
| `apps/v4/registry/bases/radix/examples/_registry.ts` | Add `stepper-example` entry (alphabetically between `spinner-example` and `switch-example`) |

---

## Key Patterns Confirmed from Codebase

- **Context sharing**: `toggle-group.tsx` uses `React.createContext` → `<Context.Provider>` in root → `React.useContext` in children. Mirror exactly.
- **Orientation layout**: `tabs.tsx` sets `data-orientation={orientation}` on root, uses `group/tabs` named group class, then `group-data-vertical/tabs:flex-col` on children. Mirror for `group/stepper` / `group/stepper-list`.
- **`data-horizontal:`/`data-vertical:` shorthand**: Tailwind v4 custom variants defined in `shadcn/tailwind.css`. `separator.tsx` uses `data-horizontal:h-px data-horizontal:w-full data-vertical:w-px data-vertical:self-stretch`.
- **`data-slot`**: Every component element gets `data-slot="component-name"`.
- **`cn-` prefix**: Every component has a `cn-component-name` marker class in its base className.
- **`data-state`**: Use `data-[state=active]:`, `data-[state=completed]:`, `data-[state=pending]:` explicit selectors (not custom variants) for step states.
- **`IconPlaceholder`**: Used in `accordion.tsx`, `breadcrumb.tsx`, `tabs-example.tsx`; import from `@/app/(create)/components/icon-placeholder`.
- **Controlled + uncontrolled**: `value`/`defaultValue`/`onValueChange` pattern (same as HTML native and Radix primitives). `defaultValue = 1`.
- **Registry `meta.links`**: Provide `docs` and `examples` URLs in `ui/_registry.ts`.
- **`cn()` utility**: Import from `@/registry/bases/radix/lib/utils`.

---

## Step 1 — Create `apps/v4/registry/bases/radix/ui/stepper.tsx`

### Sub-components exported

```
Stepper           — root container, context provider, orientation-aware layout
StepperList       — nav bar (flex row / col based on orientation)
StepperItem       — individual step wrapper, provides per-item context
StepperTrigger    — <button> that navigates to a step on click
StepperIndicator  — visual circle: shows step number or check icon when completed
StepperTitle      — <span> step title text
StepperDescription— <span> step description text
StepperSeparator  — connector line between steps (orientation-aware)
StepperPanel      — content panel, conditionally rendered when its step is active
```

### Context design

```ts
// Shared across all sub-components inside <Stepper>
StepperContext = {
  value: number                       // currently active step
  onValueChange: (step: number) => void
  orientation: "horizontal" | "vertical"
}

// Shared across sub-components inside a single <StepperItem>
StepperItemContext = {
  step: number
  isActive: boolean
  isCompleted: boolean
}
```

### Full implementation outline

```tsx
"use client"

import * as React from "react"
import { cn } from "@/registry/bases/radix/lib/utils"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

// ─── Contexts ───────────────────────────────────────────────────────────────

const StepperContext = React.createContext<{
  value: number
  onValueChange: (step: number) => void
  orientation: "horizontal" | "vertical"
}>({ value: 1, onValueChange: () => {}, orientation: "horizontal" })

const StepperItemContext = React.createContext<{
  step: number
  isActive: boolean
  isCompleted: boolean
}>({ step: 1, isActive: false, isCompleted: false })

// ─── Stepper (root) ─────────────────────────────────────────────────────────
// Controlled via `value`+`onValueChange`, or uncontrolled via `defaultValue`.
// orientation="horizontal" → root is flex-col (nav on top, panels below)
// orientation="vertical"   → root is flex-row (nav on left, panels on right)

function Stepper({
  value, defaultValue = 1, onValueChange,
  orientation = "horizontal", className, children, ...props
}: React.ComponentProps<"div"> & {
  value?: number
  defaultValue?: number
  onValueChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [internal, setInternal] = React.useState(defaultValue)
  const current = value !== undefined ? value : internal

  function handleChange(step: number) {
    if (value === undefined) setInternal(step)
    onValueChange?.(step)
  }

  return (
    <StepperContext.Provider value={{ value: current, onValueChange: handleChange, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("cn-stepper group/stepper flex gap-4 data-horizontal:flex-col", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperList ────────────────────────────────────────────────────────────
// Horizontal: flex-row items-center  (default)
// Vertical:   flex-col items-start   (via group-data-vertical/stepper)

function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-list"
      className={cn(
        "cn-stepper-list flex items-center",
        "group-data-vertical/stepper:flex-col group-data-vertical/stepper:items-start",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperItem ────────────────────────────────────────────────────────────
// Provides StepperItemContext with step index + computed state booleans.

function StepperItem({
  step, className, children, ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { value } = React.useContext(StepperContext)
  const isActive = value === step
  const isCompleted = value > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
        className={cn("cn-stepper-item flex items-center", className)}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ─────────────────────────────────────────────────────────
// Clickable button — calls onValueChange(step) from StepperItemContext.

function StepperTrigger({ className, children, ...props }: React.ComponentProps<"button">) {
  const { onValueChange } = React.useContext(StepperContext)
  const { step, isActive, isCompleted } = React.useContext(StepperItemContext)

  return (
    <button
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
      type="button"
      className={cn(
        "cn-stepper-trigger inline-flex cursor-pointer items-center gap-2 rounded-md outline-none transition-all",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onValueChange(step)}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperIndicator ───────────────────────────────────────────────────────
// Circle showing step number (pending/active) or check icon (completed).
// Accepts children to override default content.

function StepperIndicator({ className, children, ...props }: React.ComponentProps<"span">) {
  const { step, isActive, isCompleted } = React.useContext(StepperItemContext)

  return (
    <span
      data-slot="stepper-indicator"
      data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
      className={cn(
        "cn-stepper-indicator flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold tabular-nums transition-all",
        "data-[state=pending]:border-border data-[state=pending]:bg-background data-[state=pending]:text-muted-foreground",
        "data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        className
      )}
      {...props}
    >
      {children ?? (isCompleted ? (
        <IconPlaceholder
          lucide="CheckIcon"
          tabler="IconCheck"
          hugeicons="CheckMarkSquare02Icon"
          phosphor="CheckIcon"
          remixicon="RiCheckLine"
        />
      ) : (
        step
      ))}
    </span>
  )
}

// ─── StepperTitle ───────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn("cn-stepper-title text-sm font-medium", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ─────────────────────────────────────────────────────

function StepperDescription({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn("cn-stepper-description text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ───────────────────────────────────────────────────────
// Horizontal stepper: h-px flex-1 (horizontal line, fills available space)
// Vertical stepper:   w-px min-h-4 ms-4 (vertical line, indented 1rem to
//                     align with center of the size-8 / 32px indicator)

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      aria-hidden="true"
      className={cn(
        "cn-stepper-separator bg-border",
        "group-data-horizontal/stepper:h-px group-data-horizontal/stepper:flex-1",
