"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

// ─── Contexts ────────────────────────────────────────────────────────────────

interface StepperContextValue {
  value: number
  onValueChange: (step: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue>({
  value: 1,
  onValueChange: () => {},
  orientation: "horizontal",
})

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue>({
  step: 1,
  isActive: false,
  isCompleted: false,
})

// ─── Stepper (root) ──────────────────────────────────────────────────────────
//
// Supports controlled usage via `value` + `onValueChange`, or uncontrolled
// via `defaultValue`. The `orientation` prop controls layout direction:
//   "horizontal" → flex-col  (step list on top, panels below)
//   "vertical"   → flex-row  (step list on left, panels on right)

function Stepper({
  value,
  defaultValue = 1,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: number
  defaultValue?: number
  onValueChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [internal, setInternal] = React.useState(defaultValue)
  const current = value !== undefined ? value : internal

  function handleChange(step: number) {
    if (value === undefined) {
      setInternal(step)
    }
    onValueChange?.(step)
  }

  return (
    <StepperContext.Provider
      value={{ value: current, onValueChange: handleChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex gap-4 data-horizontal:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperList ─────────────────────────────────────────────────────────────
//
// The navigation bar containing step items and separators.
// Automatically lays out horizontally or vertically based on the parent
// Stepper's orientation via group-data-* selectors.

function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-list"
      className={cn(
        "cn-stepper-list flex items-center",
        "group-data-vertical/stepper:flex-col group-data-vertical/stepper:items-start",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────
//
// Wrapper for a single step. Derives `isActive` and `isCompleted` from the
// root context and exposes them via StepperItemContext for child components.

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { value } = React.useContext(StepperContext)
  const isActive = value === step
  const isCompleted = value > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
        className={cn("cn-stepper-item flex items-center", className)}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────
//
// Clickable <button> that navigates to this step when clicked.
// Reads the step number from StepperItemContext and calls onValueChange.

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = React.useContext(StepperContext)
  const { step, isActive, isCompleted } = React.useContext(StepperItemContext)

  return (
    <button
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
      type="button"
      className={cn(
        "cn-stepper-trigger inline-flex cursor-pointer items-center gap-2 rounded-md outline-none transition-all",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onValueChange(step)}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperIndicator ────────────────────────────────────────────────────────
//
// Visual circle that shows the step number when pending or active, and a
// check icon when completed. Accepts `children` to override default content.

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { step, isActive, isCompleted } = React.useContext(StepperItemContext)

  return (
    <span
      data-slot="stepper-indicator"
      data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
      className={cn(
        "cn-stepper-indicator flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold tabular-nums transition-all",
        "data-[state=pending]:border-border data-[state=pending]:bg-background data-[state=pending]:text-muted-foreground",
        "data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        className
      )}
      {...props}
    >
      {children ??
        (isCompleted ? (
          <IconPlaceholder
            lucide="CheckIcon"
            tabler="IconCheck"
            hugeicons="CheckMarkSquare02Icon"
            phosphor="CheckIcon"
            remixicon="RiCheckLine"
          />
        ) : (
          step
        ))}
    </span>
  )
}

// ─── StepperTitle ────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn("cn-stepper-title text-sm font-medium", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-xs text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────
//
// Connector line rendered between StepperItems inside a StepperList.
//   Horizontal stepper: h-px flex-1  (horizontal line filling available space)
//   Vertical stepper:   w-px min-h-4 ms-4  (vertical line, indented 1rem to
//     align with the centre of the 32px / size-8 indicator circle)

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      aria-hidden="true"
      className={cn(
        "cn-stepper-separator bg-border",
        "group-data-horizontal/stepper:h-px group-data-horizontal/stepper:flex-1",
        "group-data-vertical/stepper:ms-4 group-data-vertical/stepper:min-h-4 group-data-vertical/stepper:w-px",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ────────────────────────────────────────────────────────────
//
// Content panel shown only when its `step` matches the current context value.
// Uses conditional rendering (returns null when inactive) for simplicity.

function StepperPanel({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { value } = React.useContext(StepperContext)

  if (value !== step) return null

  return (
    <div
      data-slot="stepper-panel"
      data-state="active"
      className={cn("cn-stepper-panel flex-1", className)}
      {...props}
    />
  )
}

// ─── Exports ─────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
}
